/**
 * @param {number[]} nums
 * @return {number}
 */
function solve(nums) {
    const n = nums.length;

    // The maximum number of special indices possible is floor((n-2)/2) + 1,
    // but since we can only increase values, the maximum number of peaks
    // is at most floor((n-1)/2) if we consider the structure of peaks and valleys.
    // A pattern like [low, high, low, high, low] has peaks at indices 1, 3, 5, ...
    // The maximum number of peaks we can form is related to how many non-adjacent
    // positions we can make peaks.

    // Since increasing one element only affects its immediate neighbors' potential
    // status, and we want to maximize the count first, and then minimize cost.
    // The maximum number of peaks is floor((n-1)/2).
    // For n=3: max 1 peak (index 1). floor(2/2) = 1.
    // For n=4: max 1 peak (index 1 or 2). floor(3/2) = 1.
    // For n=5: max 2 peaks (index 1, 3). floor(4/2) = 2.

    // Let k_max be the maximum number of special indices we can achieve.
    // k_max = Math.floor((n - 1) / 2);

    // The problem seems to imply that the maximum number of special indices
    // achievable is fixed, and we only need to find the minimum cost to reach it.
    // Let's try to achieve the maximum possible number of peaks: k_max = floor((n - 1) / 2).

    // We should try to create peaks at positions i = 1, 3, 5, ..., up to n-2 (if n-2 is odd, or n-3 if n-2 is even).
    // The target peak indices are i = 1, 3, 5, ..., 2*k_max - 1.

    const targetPeaks = [];
    for (let i = 1; i < n - 1; i += 2) {
        targetPeaks.push(i);
    }

    // If we aim for peaks at 1, 3, 5, ..., we are maximizing the count.
    // Let's assume this set of indices achieves the maximum count.
    // We need to calculate the minimum cost to make nums[i] a peak for all i in targetPeaks,
    // while ensuring that the required increases for one peak do not negatively affect
    // the possibility or cost of making other peaks (especially since increasing nums[i]
    // might make nums[i-2] or nums[i+2] *not* a peak if we had chosen them).

    // Since we chose non-adjacent peaks (1, 3, 5, ...), the required increases at nums[i]
    // will only affect its neighbors nums[i-1] and nums[i+1].
    // The neighbors are indices 0, 2, 4, ... (even indices).
    // The required value at nums[i] depends on nums[i-1] and nums[i+1].
    // Since we are only increasing nums[i], the values at nums[i-1] and nums[i+1] remain
    // relatively small (their original values or values increased due to making *their* neighbors peaks,
    // which is not the case here since we only target odd indices for peaks).

    // Because the target peak indices are separated by at least 2, making nums[i] a peak
    // only requires nums[i] > nums[i-1] and nums[i] > nums[i+1].
    // The neighbors nums[i-1] and nums[i+1] are not targeted to be peaks, so their values
    // won't be aggressively increased by the algorithm's target peak formation process.
    // This suggests a greedy approach based on targetting alternating indices is optimal
    // for maximizing the count and then minimizing cost locally.

    let totalCost = 0;
    // We will process the potential peak indices in increasing order.
    for (const i of targetPeaks) {
        const left = nums[i - 1];
        const right = nums[i + 1];

        // Required value for nums[i] to be a peak:
        // nums[i] must be strictly greater than max(nums[i-1], nums[i+1]).
        const requiredValue = Math.max(left, right) + 1;

        // The cost to achieve this is max(0, requiredValue - nums[i]).
        const cost = Math.max(0, requiredValue - nums[i]);

        totalCost += cost;

        // IMPORTANT: We must conceptually update nums[i] to its new value
        // to ensure that subsequent calculations for other peaks (which might be affected if we chose non-alternating peaks,
        // but here they are separated) are based on the final state, though for the alternating case, it's safe.
        // For safety and correctness in a general greedy framework, we update the array state.
        nums[i] += cost;
    }

    // If we had chosen to target even indices (2, 4, 6, ...), the cost might be different,
    // but since the structure of the problem implies we can always achieve k_max peaks,
    // we just need to find the minimum cost configuration. By picking the alternating set (1, 3, 5, ...),
    // we are imposing the structure [low, high, low, high, ...], which is the most balanced way to
    // achieve the maximum density of peaks, thus leading to the minimum cost for that maximum count.

    return totalCost;
}

